#include<bits/stdc++.h>
using namespace std;
int a[101],b[20001];
int dp[20001];
int main(){
    int n,m;
    cin>>n>>m;
    for(int i=0;i<m;i++){
        cin>>a[i];
    }
    for(int i=0;i<n;i++){
        cin>>b[i];
    }
    memset(dp, -1e9, sizeof(dp));
    dp[0]=0;
    for(int j=0;j<n+n;j++){
        for(int i=0;i<m;i++){
            if(j>=a[i]){
                dp[j]=max(dp[j],dp[j-a[i]]+b[j-a[i]]);
            }
        }
    }
    int ans=-1e9;
    for(int i=n;i<n+n;i++){
        ans=max(ans,dp[i]);
    }
    cout<<ans;
    return 0;
}
